#include <stdio.h>
#include <stdlib.h>
#define MOD 3046201

int berries[100000];

int calculateWays(int totalBerries, int numTourists) {
    if (totalBerries < numTourists) return 0;
    if (totalBerries % numTourists == 0) return 1;
    if (totalBerries % numTourists == 1) return numTourists;
    int ways = 1;
    for (int i = 2; i <= numTourists; i++) {
        ways = (ways * i) % MOD;
    }
    return ways;
}

int main() {
    int N, Q;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        scanf("%d", &berries[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        char query[10];
        scanf("%s", query);
        if (strcmp(query, "change") == 0) {
            int A, B;
            scanf("%d %d", &A, &B);
            berries[A - 1] = B;
        } else if (strcmp(query, "query") == 0) {
            int L, R;
            scanf("%d %d", &L, &R);
            int totalBerries = 0;
            for (int j = L - 1; j < R; j++) {
                totalBerries += berries[j];
            }
            int numTourists = R - L + 1;
            int ways = calculateWays(totalBerries, numTourists);
            printf("%d\n", ways);
        }
    }
    return 0;
}

