import java.util.Scanner;
public class Main {
    static final int MOD = 3046201;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] berries = new int[N];
        for (int i = 0; i < N; i++) {
            berries[i] = scanner.nextInt();
        }
        int Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            String query = scanner.next();
            if (query.equals("change")) {
                int A = scanner.nextInt();
                int B = scanner.nextInt();
                berries[A - 1] = B;
            } else if (query.equals("query")) {
                int L = scanner.nextInt();
                int R = scanner.nextInt();
                int totalBerries = 0;
                for (int j = L - 1; j < R; j++) {
                    totalBerries += berries[j];
                }
                int numTourists = R - L + 1;
                int ways = calculateWays(totalBerries, numTourists);
                System.out.println(ways);
            }
        }
    }

    public static int calculateWays(int totalBerries, int numTourists) {
        if (totalBerries < numTourists) return 0;
        if (totalBerries % numTourists == 0) return 1;
        if (totalBerries % numTourists == 1) return numTourists;
        int ways = 1;
        for (int i = 2; i <= numTourists; i++) {
            ways = (ways * i) % MOD;
        }
        return ways;
    }
}

